#include<bits/stdc++.h>
using namespace std;
const int N=505;
int n,a[N],b[N],c[N],dp[N][N][N];
int fun(int num)
{
	return num*num;
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++) cin>>b[i];
    for(int i=1;i<=n;i++)
	{
        for(int j=i+1;j<=n;j++)
		{
            if(a[i]==a[j]) c[i]+=b[j];
        }
    }
    memset(dp,-0x3f,sizeof(dp));
    for(int i=1;i<=n;i++)
	{
        for(int j=0;j<=c[i];j++)
		{
            dp[i][i][j]=fun(b[i]+j);
        }
    }
    for(int len=2;len<=n;len++)
	{
        for(int i=1;i+len-1<=n;i++)
		{
            int j=i+len-1;
            for(int k=0;k<=c[j];k++)
			{
                dp[i][j][k]=max(dp[i][j][k],dp[i][j-1][0]+fun(b[j]+k));
            }
            for(int k=i;k<=j-2;k++)
			{
                if(a[k]!=a[j]) continue;
                for(int k2=0;k2<=c[j];k2++)
				{
                    dp[i][j][k2]=max(dp[i][j][k2],dp[i][k][b[j]+k2]+dp[k+1][j-1][0]);
                }
            }
        }
    }
    cout<<dp[1][n][0]; 
	return 0;
}
